import React, { useState } from 'react';
import { signup } from '../api/api';

function Signup({ switchToLogin }) {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [gender, setGender] = useState('');
  const [age, setAge] = useState('');
  const [city, setCity] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSignup = async () => {
    if (!name || !email || !password || !gender || !age || !city) {
      setError('Veuillez remplir tous les champs');
      return;
    }
    setLoading(true);
    setError('');
    try {
      const result = await signup({ name, email, password, gender, age: parseInt(age), city });
      alert(`🎉 Compte créé!\nBienvenue ${result.user.name} ❤️`);
      switchToLogin();
    } catch (err) {
      setError(err.message || 'Erreur lors de l\'inscription');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.imageContainer}>
        <div style={styles.sunsetOverlay}>
          <div style={styles.coupleEmoji}>👫</div>
          <div style={styles.sunEmoji}>🌅</div>
          <div style={styles.heartOverlay}>❤️</div>
        </div>
        <div style={styles.gradientOverlay}></div>
      </div>
      <div style={styles.card}>
        <h1 style={styles.title}>💕 Créer un compte</h1>
        <p style={styles.subtitle}>Rejoignez Chatalgerie ❤️</p>
        {error && <p style={styles.error}>{error}</p>}
        <input type="text" placeholder="👤 Nom complet" value={name} onChange={(e) => setName(e.target.value)} style={styles.input} />
        <input type="email" placeholder="📧 Email" value={email} onChange={(e) => setEmail(e.target.value)} style={styles.input} />
        <input type="password" placeholder="🔒 Mot de passe" value={password} onChange={(e) => setPassword(e.target.value)} style={styles.input} />
        <div style={styles.genderContainer}>
          <button style={{...styles.genderButton, backgroundColor: gender === 'femme' ? '#FF69B4' : '#f0f0f0', color: gender === 'femme' ? 'white' : '#333'}} onClick={() => setGender('femme')}>👩 Femme</button>
          <button style={{...styles.genderButton, backgroundColor: gender === 'homme' ? '#4A90D9' : '#f0f0f0', color: gender === 'homme' ? 'white' : '#333'}} onClick={() => setGender('homme')}>👨 Homme</button>
        </div>
        <input type="number" placeholder="🎂 Âge" value={age} onChange={(e) => setAge(e.target.value)} style={styles.input} />
        <input type="text" placeholder="📍 Ville" value={city} onChange={(e) => setCity(e.target.value)} style={styles.input} />
        <button onClick={handleSignup} style={styles.button} disabled={loading}>{loading ? '⏳ Inscription...' : '💕 S\'inscrire'}</button>
        <p style={styles.link} onClick={switchToLogin}>🔙 Déjà un compte? Se connecter</p>
        <div style={styles.hearts}><span style={styles.heart}>❤️</span><span style={styles.heart}>💕</span><span style={styles.heart}>❤️</span><span style={styles.heart}>💕</span><span style={styles.heart}>❤️</span></div>
      </div>
    </div>
  );
}

const styles = {
  container: { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '100vh', background: 'linear-gradient(135deg, #FFB6C1 0%, #87CEEB 100%)', fontFamily: 'Arial, sans-serif', padding: '20px' },
  imageContainer: { width: '320px', height: '100px', borderRadius: '20px', overflow: 'hidden', marginBottom: '20px', position: 'relative', boxShadow: '0 8px 30px rgba(0,0,0,0.2)', background: 'linear-gradient(180deg, #FF6B35 0%, #FF8C42 30%, #FFB347 60%, #FFD700 80%, #FF6B6B 100%)' },
  sunsetOverlay: { width: '100%', height: '100%', position: 'relative', display: 'flex', justifyContent: 'center', alignItems: 'center' },
  coupleEmoji: { fontSize: '40px', position: 'absolute', bottom: '10px', left: '50%', transform: 'translateX(-50%)', filter: 'drop-shadow(0 4px 15px rgba(0,0,0,0.3))', zIndex: 2 },
  sunEmoji: { fontSize: '45px', position: 'absolute', top: '5px', right: '15px', animation: 'sunGlow 2s infinite alternate', filter: 'drop-shadow(0 0 20px rgba(255,215,0,0.6))', zIndex: 1 },
  heartOverlay: { fontSize: '25px', position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', animation: 'heartFloat 2s infinite', filter: 'drop-shadow(0 4px 15px rgba(255,0,0,0.4))', zIndex: 3 },
  gradientOverlay: { position: 'absolute', bottom: 0, left: 0, right: 0, height: '50%', background: 'linear-gradient(0deg, rgba(0,0,0,0.2) 0%, transparent 100%)', zIndex: 0 },
  card: { backgroundColor: 'rgba(255,255,255,0.95)', borderRadius: '24px', padding: '30px', width: '100%', maxWidth: '420px', maxHeight: '90vh', overflowY: 'auto', boxShadow: '0 20px 60px rgba(0,0,0,0.15)', textAlign: 'center' },
  title: { fontSize: '2rem', fontWeight: 'bold', marginBottom: '5px', background: 'linear-gradient(45deg, #FF69B4, #4A90D9)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' },
  subtitle: { color: '#888', fontSize: '0.95rem', marginBottom: '20px', fontWeight: '500' },
  genderContainer: { display: 'flex', gap: '12px', marginBottom: '10px' },
  genderButton: { flex: 1, padding: '10px', borderRadius: '12px', fontSize: '0.95rem', fontWeight: 'bold', cursor: 'pointer', transition: 'all 0.3s ease', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' },
  input: { width: '100%', padding: '12px 14px', margin: '8px 0', borderRadius: '12px', border: '2px solid #e8e8e8', fontSize: '0.95rem', boxSizing: 'border-box', transition: 'border-color 0.3s', outline: 'none', backgroundColor: '#fafafa' },
  button: { width: '100%', padding: '14px', margin: '15px 0 12px', borderRadius: '12px', border: 'none', background: 'linear-gradient(45deg, #FF6B6B, #FF1493)', color: 'white', fontSize: '1.1rem', fontWeight: 'bold', cursor: 'pointer', transition: 'transform 0.2s', boxShadow: '0 4px 20px rgba(255,20,147,0.35)' },
  link: { color: '#4A90D9', textDecoration: 'none', cursor: 'pointer', fontSize: '0.95rem', fontWeight: '600', marginTop: '5px' },
  error: { color: '#FF1493', fontSize: '0.85rem', margin: '5px 0', fontWeight: 'bold' },
  hearts: { marginTop: '20px', display: 'flex', justifyContent: 'center', gap: '10px', flexWrap: 'wrap' },
  heart: { fontSize: '1.5rem', animation: 'pulse 1.5s infinite', display: 'inline-block' },
};

const styleSheet = document.createElement('style');
styleSheet.textContent = `
  @keyframes pulse { 0% { transform: scale(1); } 50% { transform: scale(1.3); } 100% { transform: scale(1); } }
  @keyframes sunGlow { 0% { transform: scale(1) rotate(0deg); opacity: 0.8; } 100% { transform: scale(1.1) rotate(10deg); opacity: 1; } }
  @keyframes heartFloat { 0% { transform: translate(-50%, -50%) scale(1); opacity: 0.7; } 50% { transform: translate(-50%, -60%) scale(1.2); opacity: 1; } 100% { transform: translate(-50%, -50%) scale(1); opacity: 0.7; } }
  .heart:nth-child(1) { animation-delay: 0s; } .heart:nth-child(2) { animation-delay: 0.3s; } .heart:nth-child(3) { animation-delay: 0.6s; } .heart:nth-child(4) { animation-delay: 0.9s; } .heart:nth-child(5) { animation-delay: 1.2s; }
  input:focus { border-color: #6C63FF !important; box-shadow: 0 0 0 4px rgba(108,99,255,0.15) !important; background-color: white !important; }
  button:hover:not(:disabled) { transform: scale(1.02); box-shadow: 0 6px 25px rgba(255,20,147,0.45) !important; }
  button:disabled { opacity: 0.6; cursor: not-allowed; }
  .genderButton:hover { transform: translateY(-2px); box-shadow: 0 4px 15px rgba(0,0,0,0.1); }
  .link:hover { color: #FF1493; }
`;
document.head.appendChild(styleSheet);

export default Signup;
